var e=[{id:`L3_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`하아……`,JPN:`はあ……`,ENG:`*Sigh*`,TWN:`呼……`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`조금만 더 가면 제단에 도착할 수 있어.`,JPN:`あと少しで祭壇に着く。`,ENG:`I’ll reach the altar soon.`,TWN:`就快到祭壇了。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`미나토님은 오지 못하는 걸까?`,JPN:`湊様は来れないのかしら？`,ENG:`I wonder if Mr. Nayuka is coming.`,TWN:`南裕夏是來不了嗎？`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`집에서 치나츠 널 억지로 결혼시키려 한다고?`,JPN:`家の人が千夏を無理やり結婚させようとしてるの？`,ENG:`They are marrying you off?`,TWN:`家人要逼你結婚？`},stage:{bg:`NANAHARA_03`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`도망치고 싶으면 도망치고, 하기 싫으면 싫다고 말해버려.`,JPN:`逃げたいなら逃げて、やりたくないなら嫌って言っちゃえ。`,ENG:`Run away if you will, or just tell them that you don’t want to.`,TWN:`想逃就逃，不願意就說不願意吧。`},stage:{bg:`NANAHARA_03`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`그게 평범한 거잖아?`,JPN:`それが普通だろ？`,ENG:`That’s an ordinary thing to do, isn’t it?`,TWN:`這不是很正常的嗎？`},stage:{bg:`NANAHARA_03`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:null,text:{KOREA:`그래도 정 방법이 없다고 느껴질 땐, 날 찾아와!`,JPN:`それでも本当に方法がないと思った時は、僕のところに来て！`,ENG:`If you still can’t find a way out, come and find me!`,TWN:`真的覺得沒辦法的時候，就來找我吧！`},stage:{bg:`NANAHARA_03`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:null,text:{KOREA:`곤경에 처한 사람을 돕는 건 당연한 일이니까.`,JPN:`困っている人を助けるのは、当たり前のことだから。`,ENG:`Helping someone in trouble is also an ordinary thing to do.`,TWN:`因為幫助有困難的人是理所當然的。`},stage:{bg:`NANAHARA_03`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`……그래.`,JPN:`……そうね。`,ENG:`... Yes.`,TWN:`……好。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`어쩌면, 혼자 마무리 짓는 편이 나은 걸지도 몰라.`,JPN:`もしかしたら、一人で決着をつけたほうがいいのかもしれない。`,ENG:`Maybe it’s for the best that I finish this all by myself.`,TWN:`也許一個人結束這一切比較好。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`으윽……`,JPN:`ううっ……`,ENG:`Urgh...`,TWN:`咳咳……`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`서둘러야…… 해.`,JPN:`急が……ないと…‥`,ENG:`I have to hurry...`,TWN:`要加快……動作。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SAYO_NPC_NANAHARA_SILHOUETTE`,text:{KOREA:`결국 여기까지 이르셨군요, 당주님.`,JPN:`結局ここまでいらしたのですね、ご当主。`,ENG:`So, Lady Nanahara. You’re here, finally.`,TWN:`堂主，您終於到這裡了。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`장로…… 당신이 어떻게 여길 온 거죠?`,JPN:`長老……貴方がなぜここにいるのですか？`,ENG:`Elder... How did you get here?`,TWN:`長老……怎麼會來這裡？`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`SAYO_NPC_NANAHARA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`이 땅은…… 평범한 사람이 들어와도 괜찮은 곳이 아닙니다. 어서 떠나세요.`,JPN:`この土地は……普通の人が入ってはならない危険な場所です。
すぐに戻ってください。`,ENG:`This land is dangerous for ordinary people. You must leave.`,TWN:`這個地方……不是一般人可以隨意進來的，請快離開。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`SAYO_NPC_NANAHARA_NULL`,text:{KOREA:`당주께선, 봉인 전승을 실제로 보신 적이 있으신지요?`,JPN:`ご当主は、封印の伝承を実際にご覧になったことがありますか？`,ENG:`Have you actually witnessed the sealing ritual?`,TWN:`堂主，您見過傳承封印吧？`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`SAYO_NPC_NANAHARA_NULL`,face:`UNIT_SERIOUS2`},R:null}}}];export{e as default};